<template><el-card shadow="never"><div class="toolbar"><el-input v-model="query.name" placeholder="群名或消息推送名称" clearable @keyup.enter="load"/><el-button type="primary" @click="load">查询</el-button><el-button type="success" @click="openCreate">新建消息推送</el-button></div>
<el-alert title="群名用于管理归类；同一个企微群可以创建多个不同用途的消息推送。系统标识自动生成。" type="info" :closable="false"/>
<el-table :data="rows" v-loading="loading" border stripe style="margin-top:14px"><el-table-column prop="groupName" label="群名"/><el-table-column prop="pushName" label="消息推送名称"/><el-table-column label="状态" width="90"><template #default="{row}"><el-tag :type="row.pushStatus===1?'success':'info'">{{row.pushStatus===1?'启用':'停用'}}</el-tag></template></el-table-column><el-table-column prop="webhookUrl" label="Webhook"/><el-table-column prop="lastTestedAt" label="最后测试" width="170"/><el-table-column label="操作" width="190"><template #default="{row}"><el-button link @click="openEdit(row)">编辑</el-button><el-button link type="warning" @click="test(row)">测试</el-button><el-button link type="danger" @click="disable(row)">停用</el-button></template></el-table-column></el-table>
<el-pagination class="pager" background layout="prev,pager,next,total" :total="total" :page-size="query.size" @current-change="(p:number)=>{query.page=p;load()}"/>
<el-dialog v-model="dialog" :title="form.id?'编辑消息推送':'新建消息推送'" width="580px"><el-form label-width="130px"><el-form-item label="群名" required><el-input v-model="form.groupName" placeholder="如：运营中心群"/></el-form-item><el-form-item label="消息推送名称" required><el-input v-model="form.pushName" placeholder="如：日常督办推送"/></el-form-item><el-form-item label="Webhook" required><el-input v-model="form.webhookUrl" placeholder="https://qyapi.weixin.qq.com/cgi-bin/webhook/send?key=..."/></el-form-item><el-form-item label="状态"><el-switch v-model="form.enabled" active-text="启用"/></el-form-item><el-form-item label="备注"><el-input v-model="form.remark" type="textarea"/></el-form-item></el-form><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="save">保存</el-button></template></el-dialog></el-card></template>
<script setup lang="ts">import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{listRobots,createRobot,updateRobot,deleteRobot,testRobot}from'@/api';const rows=ref<any[]>([]),total=ref(0),loading=ref(false),dialog=ref(false),saving=ref(false);const query=reactive({name:'',page:1,size:10});const form=reactive<any>({id:0,groupName:'',pushName:'',webhookUrl:'',enabled:true,remark:''});async function load(){loading.value=true;try{const r=await listRobots(query);rows.value=r.data.data?.records??[];total.value=r.data.data?.total??0}finally{loading.value=false}}function openCreate(){Object.assign(form,{id:0,groupName:'',pushName:'',webhookUrl:'',enabled:true,remark:''});dialog.value=true}function openEdit(row:any){Object.assign(form,{id:row.id,groupName:row.groupName,pushName:row.pushName,webhookUrl:'******',enabled:row.pushStatus===1,remark:''});dialog.value=true}async function save(){if(!form.groupName.trim()||!form.pushName.trim()||(!form.id&&!form.webhookUrl.trim()))return ElMessage.warning('请填写群名、消息推送名称和 Webhook');saving.value=true;try{const p={groupName:form.groupName,pushName:form.pushName,webhookUrl:form.webhookUrl,status:form.enabled?1:0,remark:form.remark};form.id?await updateRobot(form.id,p):await createRobot(p);dialog.value=false;ElMessage.success('已保存');load()}finally{saving.value=false}}async function test(row:any){await testRobot(row.id);ElMessage.success('测试发送成功');load()}async function disable(row:any){await ElMessageBox.confirm('停用后新任务不能选择该消息推送，确认继续？');await deleteRobot(row.id);ElMessage.success('已停用');load()}onMounted(load)</script><style scoped>.toolbar{display:flex;gap:10px;margin-bottom:14px}.toolbar .el-input{width:240px}.pager{margin-top:14px;justify-content:flex-end}</style>
